				    	this.util.addStyleClass(target,"nsCellFocus");
						this.__dispatchEvent(NSGrid.CELL_SELECTED,item,{cellIndex:index,rowIndex:rowIndex,item:item,cell:target,row:row});
						this.__lastBodyCellFocus = target;
